"use strict";(self.webpackChunkmy_blog=self.webpackChunkmy_blog||[]).push([[17895],{66262:(n,s)=>{s.A=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}},28716:(n,s,a)=>{a.r(s),a.d(s,{comp:()=>t,data:()=>m});var e=a(20641);const i=a.p+"assets/img/58f59680-2d68-11ea-a743-8137f2e46c91.42d0b481.png",l=a.p+"assets/img/629d8300-2d68-11ea-a743-8137f2e46c91.1436f93a.png",p=a.p+"assets/img/6bd52180-2d68-11ea-b8bc-595e31068820.65d72e53.png",c=a.p+"assets/img/7c66ebf0-2d68-11ea-b6a8-fbb27a899f8c.c2cd1a2e.png",d=a.p+"assets/img/84cfa1b0-2d68-11ea-8fee-9f496e85c50f.cd1083e5.png",r=a.p+"assets/img/8cb2acb0-2d68-11ea-b6fe-19eaa05aac2e.9117e731.png",v={},t=(0,a(66262).A)(v,[["render",function(n,s){return(0,e.uX)(),(0,e.CE)("div",null,s[0]||(s[0]=[(0,e.Fv)('<h1 id="_12-jmx-与相关工具-山高月小-水落石出" tabindex="-1"><a class="header-anchor" href="#_12-jmx-与相关工具-山高月小-水落石出"><span>12 JMX 与相关工具：山高月小，水落石出</span></a></h1><h1 id="_12-jmx-与相关工具-山高月小-水落石出-1" tabindex="-1"><a class="header-anchor" href="#_12-jmx-与相关工具-山高月小-水落石出-1"><span>12 JMX 与相关工具：山高月小，水落石出</span></a></h1><p>Java 平台提供了全面的 JVM 监控和管理措施。</p><p>在 Java SE 5 之前，虽然 JVM 提供了一些底层的 API，比如 JVMPI 和 JVMTI，但这些 API 都是面向 C 语言的，需要通过 JNI 等方式才能调用，想要监控 JVM 和系统资源非常不方便。</p><p>Java SE 5.0 版本引入了 JMX 技术（Java Management Extensions，Java 管理扩展），JMX 技术的前身是“JSR3:Java Management Extensions”，以及“JSR 160:JMX Remote API”。</p><p>JMX 是用于监控和管理 JVM 资源（包括应用程序、设备、服务和 JVM）的一组标准 API。</p><p>通过这些 API 接口，可以对外暴露 JVM 和宿主机的一些信息，甚至支持远程动态调整某些运行时参数。</p><p>JMX 技术让我们在 JDK 中开发自检程序成为可能，同时也提供了很多轻量级的 API 来监测 JVM 状态和运行中对象/线程状态，从而提高了 Java 语言自身的管理监测能力。</p><p>客户端使用 JMX 主要通过两种方式：</p><ul><li>程序代码手动获取 MXBean；</li><li>通过网络远程获取 MBean。 从 JVM 运行时获取 GC 行为数据，最简单的办法是使用标准 JMX API 接口。JMX 也是获取 JVM 内部运行时状态信息 的标准 API。可以编写程序代码，通过 JMX API 来访问本程序所在的 JVM，也可以通过 JMX 客户端执行（远程）访问。MXBean 可用于监控和管理 JVM，每个 MXBean 都封装了一部分功能。</li></ul><p>如果用通俗的话来讲，就是我们可以在 JVM 这个机构内部搞一个“政务信息公开系统”，这个东西就可以看做是 MBeanServer，然后系统默认有很多信息，比如 JVM 的基本信息、内存和 GC 的信息等，可以放到这个系统来公开。应用程序里的其他 Java 代码也可以自己定义一些 MBean，然后把这些自己想要公开的信息挂到这个系统里来。这个时候，就不管是本 JVM 内部，还是其他的 Java 应用程序，都可以访问到这个 MBeanServer 上的所有公开信息，也就是 MBean 的属性，甚至可以直接调用 MBean 提供的方法反过来影响系统。</p><h2 id="获取当前-jvm-的-mxbean-信息" tabindex="-1"><a class="header-anchor" href="#获取当前-jvm-的-mxbean-信息"><span>获取当前 JVM 的 MXBean 信息</span></a></h2><p>JDK 默认提供的 MXBean 相关类，主要位于 rt.jar 文件的 java.lang.management 包中。获取 JVM 中 MXBean 信息的代码示例如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>package jvm.chapter11;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import com.alibaba.fastjson.JSON;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import com.alibaba.fastjson.serializer.*;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.lang.management.*;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.util.*;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>public class MXBeanTest {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public static void main(String[] args) {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        Map&lt;String, Object&gt; beansMap = loadMXBeanMap();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        String jsonString = toJSON(beansMap);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        System.out.println(jsonString);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public static Map&lt;String, Object&gt; loadMXBeanMap() {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // import java.lang.management.*</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 1. 操作系统信息</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        OperatingSystemMXBean operatingSystemMXBean =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getOperatingSystemMXBean();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 2. 运行时</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        RuntimeMXBean runtimeMXBean =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getRuntimeMXBean();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 3.1 JVM 内存信息</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        MemoryMXBean memoryMXBean =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getMemoryMXBean();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 3.2 JVM 内存池-列表</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        List&lt;MemoryPoolMXBean&gt; memoryPoolMXBeans =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getMemoryPoolMXBeans();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 3.3 内存管理器-列表</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        List&lt;MemoryManagerMXBean&gt; memoryManagerMXBeans =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getMemoryManagerMXBeans();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 4. class 加载统计信息</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        ClassLoadingMXBean classLoadingMXBean =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getClassLoadingMXBean();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 5. 编译统计信息</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        CompilationMXBean compilationMXBean =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getCompilationMXBean();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 6. 线程</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        ThreadMXBean threadMXBean =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getThreadMXBean();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 7. GC</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        List&lt;GarbageCollectorMXBean&gt; garbageCollectorMXBeans =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getGarbageCollectorMXBeans();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // 8. 获取平台日志 MXBean</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        PlatformLoggingMXBean platformLoggingMXBean =</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ManagementFactory.getPlatformMXBean(PlatformLoggingMXBean.class);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        //</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        Map&lt;String, Object&gt; beansMap = new HashMap&lt;String, Object&gt;();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        //</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;operatingSystemMXBean&quot;, operatingSystemMXBean);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;runtimeMXBean&quot;, runtimeMXBean);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;memoryMXBean&quot;, memoryMXBean);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;memoryPoolMXBeans&quot;, memoryPoolMXBeans);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;memoryManagerMXBeans&quot;, memoryManagerMXBeans);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;classLoadingMXBean&quot;, classLoadingMXBean);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;compilationMXBean&quot;, compilationMXBean);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;threadMXBean&quot;, threadMXBean);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;garbageCollectorMXBeans&quot;, garbageCollectorMXBeans);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        beansMap.put(&quot;platformLoggingMXBean&quot;, platformLoggingMXBean);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        return beansMap;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public static String toJSON(Object obj) {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        // MemoryPoolMXBean 这些未设置的属性序列化时会报错</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        SimplePropertyPreFilter filter = new SimplePropertyPreFilter();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        filter.getExcludes().add(&quot;collectionUsageThreshold&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        filter.getExcludes().add(&quot;collectionUsageThresholdCount&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        filter.getExcludes().add(&quot;collectionUsageThresholdExceeded&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        filter.getExcludes().add(&quot;usageThreshold&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        filter.getExcludes().add(&quot;usageThresholdCount&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        filter.getExcludes().add(&quot;usageThresholdExceeded&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        //</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        String jsonString = JSON.toJSONString(obj, filter, </span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                SerializerFeature.PrettyFormat);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        return jsonString;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>取得这些 MXBean 之后，就能采集到对应的 Java 运行时信息，定时上报给某个系统，那么一个简单的监控就创建了。</p><p>当然，这么简单的事情，肯定有现成的轮子啦。比如 Spring Boot Actuator，以及后面介绍的 Micrometer 等。各种监控服务提供的 Agent-lib 中也会通过类似的手段采集相应的数据。</p><p>如果想通过编程方式获取远程机器上的 MXBean，请参考：</p><p><a href="https://docs.oracle.com/javase/8/docs/technotes/guides/management/mxbeans.html" target="_blank" rel="noopener noreferrer">Using the Platform MBean Server and Platform MXBeans</a></p><h2 id="使用-jmx-工具远程连接" tabindex="-1"><a class="header-anchor" href="#使用-jmx-工具远程连接"><span>使用 JMX 工具远程连接</span></a></h2><p>最常见的 JMX 客户端是 JConsole 和 JVisualVM（可以安装各种插件，十分强大）。两个工具都是标准 JDK 的一部分，而且很容易使用. 如果使用的是 JDK 7u40 及更高版本，还可以使用另一个工具：Java Mission Control（JMC，大致翻译为 Java 控制中心）。</p><p>监控本地 JVM 并不需要额外配置，如果是远程监控，还可以在服务端部署 Jstatd 服务暴露部分信息给 JMX 客户端。</p><p>所有 JMX 客户端都是独立的程序，可以连接到目标 JVM 上。目标 JVM 可以在本机，也可以是远端 JVM。</p><p>想要支持 JMX 客户端连接服务端 JVM 实例，则 Java 启动脚本中需要加上相关的配置参数，示例如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>-Dcom.sun.management.jmxremote</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>-Dcom.sun.management.jmxremote.port=10990</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>-Dcom.sun.management.jmxremote.ssl=false</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>-Dcom.sun.management.jmxremote.authenticate=false</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果服务器具有多张网卡（多个 IP），由于安全限制，必须明确指定 hostname， 一般是 IP。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>-Djava.rmi.server.hostname=47.57.227.67</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>这样启动之后，JMX 客户端（如 JConsole、JVisualVM、JMC）就可以通过 <code>&lt;IP:端口&gt;</code> 连接。(参考 JVisualVM 的示例）。</p><p>如这里对应的就类似于：47.57.227.67:10990。</p><p>如果想要远程查看 VisualGC，则服务端需要开启 Jstatd 来支持，JVisualVM 先连 Jstatd 远程主机，接着在远程主机上点右键添加 JMX 连接。关于 JVisualVM 的使用，请参考前面的文章《JDK 内置图形界面工具》。</p><p>以 JConsole 为例，我们看一下，连接到了远程 JVM 以后，在最后一个面板即可看到 MBean 信息。</p><p>例如，我们可以查看 JVM 的一些信息：</p><figure><img src="'+i+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>也可以直接调用方法，例如查看 VM 参数：</p><figure><img src="'+l+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>如果启动的进程是 Tomcat 或者是 Spring Boot 启动的嵌入式 Tomcat，那么我们还可以看到很多 Tomcat 的信息：</p><figure><img src="'+p+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="jmx-的-mbean-创建和远程访问" tabindex="-1"><a class="header-anchor" href="#jmx-的-mbean-创建和远程访问"><span>JMX 的 MBean 创建和远程访问</span></a></h2><p>前面讲了在同一个 JVM 里获取 MBean，现在我们再来写一个更完整的例子：创建一个 MBean，然后远程访问它。</p><p>先定义一个 UserMBean 接口（必须以 MBean 作为后缀）：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>package io.github.kimmking.jvmstudy.jmx;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>public interface UserMBean {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    Long getUserId();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    String getUserName();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    void setUserId(Long userId);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    void setUserName(String userName);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后实现它：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>package io.github.kimmking.jvmstudy.jmx;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>public class User implements UserMBean {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    Long userId = 12345678L;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    String userName = &quot;jvm-user&quot;;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public Long getUserId() {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        return userId;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public String getUserName() {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        return userName;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void setUserId(Long userId) {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        this.userId = userId;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    @Override</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public void setUserName(String userName) {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        this.userName = userName;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>最后实现一个类来启动 MBeanServer：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>package io.github.kimmking.jvmstudy.jmx;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.MBeanServer;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.MBeanServerFactory;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.ObjectName;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.remote.JMXConnectorServer;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.remote.JMXConnectorServerFactory;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.remote.JMXServiceURL;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.lang.management.ManagementFactory;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.rmi.registry.LocateRegistry;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.rmi.registry.Registry;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>public class UserJmxServer {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public static void main(String[] args){</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        MBeanServer server;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        User bean=new User();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        try {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            int rmiPort = 1099;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            String jmxServerName = &quot;TestJMXServer&quot;;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            Registry registry = LocateRegistry.createRegistry(rmiPort);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            server = MBeanServerFactory.createMBeanServer(&quot;user&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            ObjectName objectName = new ObjectName(&quot;user:name=User&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            server.registerMBean(bean, objectName);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            JMXServiceURL url = new JMXServiceURL(&quot;service:jmx:rmi:///jndi/rmi://localhost:1099/user&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;JMXServiceURL: &quot; + url.toString());</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            JMXConnectorServer jmxConnServer = JMXConnectorServerFactory.newJMXConnectorServer(url, null, server);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            jmxConnServer.start();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        }catch (Exception e){</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            e.printStackTrace();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过这几个代码我们可以看到，使用 MBean 机制，需要：</p><ul><li>先定义 MBean 接口；</li><li>实现这个接口；</li><li>然后把接口和类，注册到 MBeanServer，这里可以用 JVM 里的默认 MBeanServer，也可以自己创建一个新的 Server，这里为了简单，就使用了默认的。 然后我们就可以使用客户端工具或者代码来访问 MBeanServer，查看和操作 MBean，由于 MBean 类似反射的机制（如果早期做过 Windows 平台的 COM 对象开发，就会发现是类似的），客户端不需要知道具体的 MBean 接口或者实现类，也能请求服务器端。</li></ul><p>如果大家学习过 Apache Dubbo，就知道在 Dubbo 里消费端必须拿到服务提供者的服务接口，才能配置和调用，这里不同的地方就是客户端是不需要 MBean 接口的。</p><h3 id="jconsole-里查看自定义-mbean" tabindex="-1"><a class="header-anchor" href="#jconsole-里查看自定义-mbean"><span>JConsole 里查看自定义 MBean</span></a></h3><p>首先我们启动这个应用 UserJmxServer，接下来我们使用工具来查看和操作它。</p><p>打开 JConsole，在远程输入：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>service:jmx:rmi:///jndi/rmi://localhost:1099/user</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><figure><img src="'+c+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>查看 User 的属性：</p><figure><img src="'+d+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>直接修改 UserName 的值：</p><figure><img src="'+r+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="使用-jmx-远程访问-mbean" tabindex="-1"><a class="header-anchor" href="#使用-jmx-远程访问-mbean"><span>使用 JMX 远程访问 MBean</span></a></h3><p>我们先使用 JMXUrl 来创建一个 MBeanServerConnection，连接到 MBeanServer，然后就可以通过 ObjectName，也可以看做是 MBean 的地址，像反射一样去拿服务器端 MBean 里的属性，或者调用 MBean 的方法。示例如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>package io.github.kimmking.jvmstudy.jmx;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.*;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import javax.management.remote.*;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.rmi.registry.LocateRegistry;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.rmi.registry.Registry;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.util.Iterator;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>import java.util.Set;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>public class UserJmxClient {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    public static void main(String[] args){</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        try {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            String surl = &quot;service:jmx:rmi:///jndi/rmi://localhost:1099/user&quot;;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            JMXServiceURL url = new JMXServiceURL(surl);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            JMXConnector jmxc = JMXConnectorFactory.connect(url, null);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            MBeanServerConnection mbsc = jmxc.getMBeanServerConnection();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;Domains:---------------&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            String domains[] = mbsc.getDomains();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            for (int i = 0; i &lt; domains.length; i++) {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                System.out.println(&quot;\\tDomain[&quot; + i + &quot;] = &quot; + domains[i]);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;all ObjectName：---------------&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            Set&lt;ObjectInstance&gt; set = mbsc.queryMBeans(null, null);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            for (Iterator&lt;ObjectInstance&gt; it = set.iterator(); it.hasNext();) {</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                ObjectInstance objectInstance = (ObjectInstance) it.next();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                System.out.println(&quot;\\t&quot; + objectInstance.getObjectName() + &quot; =&gt; &quot; + objectInstance.getClassName());</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;user:name=User：---------------&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            ObjectName mbeanName = new ObjectName(&quot;user:name=User&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            MBeanInfo info = mbsc.getMBeanInfo(mbeanName);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;Class: &quot; + info.getClassName());</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            if (info.getAttributes().length &gt; 0){</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                for(MBeanAttributeInfo m : info.getAttributes())</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                    System.out.println(&quot;\\t ==&gt; Attriber：&quot; + m.getName());</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            if (info.getOperations().length &gt; 0){</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                for(MBeanOperationInfo m : info.getOperations())</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>                    System.out.println(&quot;\\t ==&gt; Operation：&quot; + m.getName());</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;Testing userName and userId .......&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            Object userNameObj = mbsc.getAttribute(mbeanName,&quot;UserName&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;\\t ==&gt; userName：&quot; + userNameObj);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            Object userIdObj = mbsc.getAttribute(mbeanName,&quot;UserId&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;\\t ==&gt; userId：&quot; + userIdObj);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            Attribute userNameAttr = new Attribute(&quot;UserName&quot;,&quot;kimmking&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            mbsc.setAttribute(mbeanName,userNameAttr);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;Modify UserName .......&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            userNameObj = mbsc.getAttribute(mbeanName,&quot;UserName&quot;);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            System.out.println(&quot;\\t ==&gt; userName：&quot; + userNameObj);</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            jmxc.close();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        }catch (Exception e){</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>            e.printStackTrace();</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>        }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>    }</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>直接运行，输出如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>Domains:---------------</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span> Domain[0] = JMImplementation</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span> Domain[1] = user</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>all ObjectName：---------------</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span> JMImplementation:type=MBeanServerDelegate =&gt; javax.management.MBeanServerDelegate</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span> user:name=User =&gt; io.github.kimmking.jvmstudy.jmx.User</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>user:name=User：---------------</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Class: io.github.kimmking.jvmstudy.jmx.User</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  ==&gt; Attriber：UserName</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  ==&gt; Attriber：UserId</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Testing userName and userId .......</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  ==&gt; userName：jvm-user</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  ==&gt; userId：12345678</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Modify UserName .......</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>  ==&gt; userName：kimmking</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在前面的 JConsole 示例中，我们可以看到 JMX 的 MBeanServer 里的所有 MBean 就是一个树结构，那么怎么定位一个 MBean 对象，就是靠它的地址，ObjectName 属性，例如例子里的 <code>user:name=User</code>。ObjectName 跟 LDAP 里定位的 DN 非常像，可以直接在客户端拿到一个服务端实际对象的代理对象。然后进行操作：</p><ul><li>queryMBeans：查询当前 Server 的所有 MBean 对象，进而可以拿到每个 MBean 内的 MBeanInfo 信息，有什么属性和方法。</li><li>getAttribute：从 Server 上拿到某个 MBean 对象的某个属性值。</li><li>setAttribute：设置 Server 上的某个 MBean 的某个属性值。</li><li>invoke：调用 Server 上某个 MBean 的某个方法。 从上面的分析，我们可以看到，JMX 其实是基于 MBean 和 MBeanServer 模型、RMI 协议，在设计上非常精巧的远程调用技术。通过学习这个技术的细节，我们可以了解一般的 RPC 等技术。学会了这种 JVM 默认的管理 API 技术，我们也可以更方便的了解和分析 JVM 情况。</li></ul><h2 id="更多用法" tabindex="-1"><a class="header-anchor" href="#更多用法"><span>更多用法</span></a></h2><p>JMX 是基于 RMI 的 JVM 管理技术，底层是 Java 平台专有的 RMI 远程方法调用，很难做到跨语言调用。怎么才能做到跨平台呢？现在最火的远程调用方式非 REST 莫属。能否让 JMX 使用 REST API 直接调用呢？答案是肯定的。</p><p>另外，想要进行性能分析，只有 JVM 的信息还是不够的，我们还需要跟其他的各类监控集成，比如 Datadog 或是其他 APM，本篇只是简单涉及。</p><h3 id="jmx-与-rest-api" tabindex="-1"><a class="header-anchor" href="#jmx-与-rest-api"><span>JMX 与 REST API</span></a></h3><p>先说一下 JMX 的 REST API，有一个框架 Jolokia，它可以自动把 JMX 的结构转换成 REST API 和 JSON 数据。在开源软件 ActiveMQ 的控制台里就默认使用了这个框架，这样可以直接达到如下效果。</p><p>我们使用 curl 手工执行一次 REST 调用，会直接返回给我们 API 的 JSON 结果。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" data-title="" style="--shiki-light:#383A42;--shiki-dark:#abb2bf;--shiki-light-bg:#FAFAFA;--shiki-dark-bg:#282c34;"><pre class="shiki shiki-themes one-light one-dark-pro vp-code"><code><span class="line"><span>$ curl http://localhost:8161/hawtio/jolokia/read/org.apache.activemq:brokerName=localhost,type=Broker/Queues</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>{&quot;timestamp&quot;:1392110578,&quot;status&quot;:200,&quot;request&quot;:{&quot;mbean&quot;:&quot;org.apache.activemq:brokerName=localhost,type=Broker&quot;,&quot;attribute&quot;:&quot;Queues&quot;,&quot;type&quot;:&quot;read&quot;},&quot;value&quot;:[{&quot;objectName&quot;:&quot;org.apache.activemq:brokerName=localhost,destinationName=a,destinationType=Queue,type=Broker&quot;}]}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>更多信息，可以阅读参考材料。</p><h3 id="jmx-与其他软件" tabindex="-1"><a class="header-anchor" href="#jmx-与其他软件"><span>JMX 与其他软件</span></a></h3><p>JConsole 及 JVisualVM 等工具提供了实时查看的能力，但如果我们想监控大量 JVM 实例的历史数据，应该怎么办呢?</p><p>既然 JMX 提供了这些数据，只要我们有一个工具来定时采集，并上报给对应的 APM 收集系统，那么我们就保存了长期的历史数据，作为进一步分析和性能诊断的依据。</p><p>例如 DataDog，听云等服务提供商都集成了对 JMX 的支持。</p><p>因为我们的专栏主要讲解 JDK 相关工具的用法，所以想了解的同学请搜索关键字，如：“Datadog JMX”或者“听云 JMX”等等。</p><p>如果你搜索“Spring JMX“，甚至能看到 JMX 可以把很多东西玩出花来，但 JMX 比起 HTTP API 来说还是比较重的，所以对于具有编程能力的企业和工程师来说，想要灵活和方便的话，HTTP 接口才是最方便的方式。</p><h2 id="相关链接" tabindex="-1"><a class="header-anchor" href="#相关链接"><span>相关链接</span></a></h2><ul><li><a href="https://docs.oracle.com/javase/8/docs/technotes/guides/jmx/index.html" target="_blank" rel="noopener noreferrer">Java Management Extensions (JMX) Guide</a></li><li><a href="https://docs.oracle.com/javase/8/docs/technotes/guides/management/index.html" target="_blank" rel="noopener noreferrer">Monitoring and Management for the Java Platform</a></li><li><a href="https://blog.csdn.net/kimmking/article/details/9170563" target="_blank" rel="noopener noreferrer">在 ActiveMQ 中使用 JMX</a></li><li><a href="https://jolokia.org/" target="_blank" rel="noopener noreferrer">Jolokia is remote JMX with JSON over HTTP.</a></li><li><a href="https://blog.csdn.net/KimmKing/article/details/19081973" target="_blank" rel="noopener noreferrer">ActiveMQ REST Management API</a></li></ul>',79)]))}]]),m=JSON.parse('{"path":"/column/JVM%E6%A0%B8%E5%BF%83%E6%8A%80%E6%9C%AF32%E8%AE%B2/12%20JMX%20%E4%B8%8E%E7%9B%B8%E5%85%B3%E5%B7%A5%E5%85%B7%EF%BC%9A%E5%B1%B1%E9%AB%98%E6%9C%88%E5%B0%8F%EF%BC%8C%E6%B0%B4%E8%90%BD%E7%9F%B3%E5%87%BA.html","title":"12 JMX 与相关工具：山高月小，水落石出","lang":"zh-CN","frontmatter":{"title":"12 JMX 与相关工具：山高月小，水落石出","breadcrumb":false,"description":"12 JMX 与相关工具：山高月小，水落石出 12 JMX 与相关工具：山高月小，水落石出 Java 平台提供了全面的 JVM 监控和管理措施。 在 Java SE 5 之前，虽然 JVM 提供了一些底层的 API，比如 JVMPI 和 JVMTI，但这些 API 都是面向 C 语言的，需要通过 JNI 等方式才能调用，想要监控 JVM 和系统资源非常...","head":[["meta",{"property":"og:url","content":"https://chenmingxing1012.github.io/blog/column/JVM%E6%A0%B8%E5%BF%83%E6%8A%80%E6%9C%AF32%E8%AE%B2/12%20JMX%20%E4%B8%8E%E7%9B%B8%E5%85%B3%E5%B7%A5%E5%85%B7%EF%BC%9A%E5%B1%B1%E9%AB%98%E6%9C%88%E5%B0%8F%EF%BC%8C%E6%B0%B4%E8%90%BD%E7%9F%B3%E5%87%BA.html"}],["meta",{"property":"og:site_name","content":"凡人修码传"}],["meta",{"property":"og:title","content":"12 JMX 与相关工具：山高月小，水落石出"}],["meta",{"property":"og:description","content":"12 JMX 与相关工具：山高月小，水落石出 12 JMX 与相关工具：山高月小，水落石出 Java 平台提供了全面的 JVM 监控和管理措施。 在 Java SE 5 之前，虽然 JVM 提供了一些底层的 API，比如 JVMPI 和 JVMTI，但这些 API 都是面向 C 语言的，需要通过 JNI 等方式才能调用，想要监控 JVM 和系统资源非常..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-06-02T15:35:54.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-02T15:35:54.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"12 JMX 与相关工具：山高月小，水落石出\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-06-02T15:35:54.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"韩跑跑\\",\\"url\\":\\"https://chenmingxing1012.github.io/blog/\\"}]}"]]},"headers":[{"level":2,"title":"获取当前 JVM 的 MXBean 信息","slug":"获取当前-jvm-的-mxbean-信息","link":"#获取当前-jvm-的-mxbean-信息","children":[]},{"level":2,"title":"使用 JMX 工具远程连接","slug":"使用-jmx-工具远程连接","link":"#使用-jmx-工具远程连接","children":[]},{"level":2,"title":"JMX 的 MBean 创建和远程访问","slug":"jmx-的-mbean-创建和远程访问","link":"#jmx-的-mbean-创建和远程访问","children":[{"level":3,"title":"JConsole 里查看自定义 MBean","slug":"jconsole-里查看自定义-mbean","link":"#jconsole-里查看自定义-mbean","children":[]},{"level":3,"title":"使用 JMX 远程访问 MBean","slug":"使用-jmx-远程访问-mbean","link":"#使用-jmx-远程访问-mbean","children":[]}]},{"level":2,"title":"更多用法","slug":"更多用法","link":"#更多用法","children":[{"level":3,"title":"JMX 与 REST API","slug":"jmx-与-rest-api","link":"#jmx-与-rest-api","children":[]},{"level":3,"title":"JMX 与其他软件","slug":"jmx-与其他软件","link":"#jmx-与其他软件","children":[]}]},{"level":2,"title":"相关链接","slug":"相关链接","link":"#相关链接","children":[]}],"git":{"createdTime":1780410159000,"updatedTime":1780414554000,"contributors":[{"name":"chenmingxing","email":"1060303243@qq.com","commits":2}]},"readingTime":{"minutes":10.64,"words":3192},"filePathRelative":"column/JVM核心技术32讲/12 JMX 与相关工具：山高月小，水落石出.md","localizedDate":"2026年6月2日","excerpt":"\\n<h1>12 JMX 与相关工具：山高月小，水落石出</h1>\\n<p>Java 平台提供了全面的 JVM 监控和管理措施。</p>\\n<p>在 Java SE 5 之前，虽然 JVM 提供了一些底层的 API，比如 JVMPI 和 JVMTI，但这些 API 都是面向 C 语言的，需要通过 JNI 等方式才能调用，想要监控 JVM 和系统资源非常不方便。</p>\\n<p>Java SE 5.0 版本引入了 JMX 技术（Java Management Extensions，Java 管理扩展），JMX 技术的前身是“JSR3:Java Management Extensions”，以及“JSR 160:JMX Remote API”。</p>","autoDesc":true}')}}]);